class Solution {
    public String arrangeWords(String text) {
        String[] words = text.split(" ");
        String firstWord = words[0].toLowerCase();
        String[] restWords = Arrays.copyOfRange(words, 1, words.length);
        Arrays.sort(restWords, (a, b) -> a.length() - b.length());
        StringBuilder sb = new StringBuilder();
        sb.append(Character.toUpperCase(firstWord.charAt(0))).append(firstWord.substring(1));
        for (String word : restWords) {
            sb.append(" ").append(word);
        }
        return sb.toString();
    }
}
